/**
 * 魔人化世界书开关（仅改名称含「魔人化」条目的 strategy.type）
 *
 * - 顶层输入框含「魔人化启动」→ 蓝灯；**最后一楼为用户且正文含该关键字**（刚发送、输入框已空）也会保持蓝灯。
 * - 转绿灯：聊天**最新楼层号**（`getLastMessageId()`）每变一次算「一楼」；若该时刻读到 `魔人化` **明确为 false** 则连击 +1，否则连击清零。**连击 ≥ 2** 且当前仍为明确 false、且输入框无关键字 → 绿灯（不再要求「最后一楼不是用户+关键字」，避免迟迟不变绿）。
 * - `魔人化` 为 undefined 等不当作关。
 *
 * 调试：
 * - 将下方 `MAJIN_WB_DEBUG_FORCE` 改为 `true` 并重新打包；或
 * - 在**本脚本 iframe** 的控制台执行：
 *   `localStorage.setItem('MajinizationWorldbookToggle:debug','1')` 后重载脚本。
 * - 关闭：`localStorage.removeItem('MajinizationWorldbookToggle:debug')`
 * - 任意时刻可手动：`__majinWbDump()`、`__majinWbDumpEntries()`（会挂到 `window` / `top`）
 */

const LAUNCH_TEXT = '魔人化启动';
const ENTRY_NAME_INCLUDES = '魔人化';
const MAJIN_KEY = '魔人化';

/** 改为 true 后重新 build，无需 localStorage 也会打日志 */
const MAJIN_WB_DEBUG_FORCE = false;

const LS_DEBUG_KEY = 'MajinizationWorldbookToggle:debug';

const DEBOUNCE_MS = 200;
const HERO_POLL_MS = 900;

/** 魔人化明确为 false 需累计多少「新楼层」事件后才允许转绿灯（用户发 + AI 回 = 2） */
const FALSE_STREAK_FLOORS_NEEDED = 2;

const LOG_PREFIX = '[魔人化世界书]';

function majinWbDebugEnabled(): boolean {
  if (MAJIN_WB_DEBUG_FORCE) return true;
  try {
    return globalThis.localStorage?.getItem(LS_DEBUG_KEY) === '1';
  } catch {
    return false;
  }
}

function majinWbLog(...args: unknown[]): void {
  if (!majinWbDebugEnabled()) return;
  console.info(LOG_PREFIX, ...args);
}

function exposeDebugHelpers(): void {
  const dump = () => {
    const o = {
      primaryWb: getPrimaryWorldbookName(),
      textareaLen: readTopSendTextareaText().length,
      textareaPreview: readTopSendTextareaText().slice(0, 100),
      textHasLaunch: readTopSendTextareaText().includes(LAUNCH_TEXT),
      lastMessageIsUserWithLaunch: lastMessageIsUserWithLaunch(),
      raw主角魔人化: getHeroValue(MAJIN_KEY),
      holdMajinWorldbook,
      majinFalseStreakCount,
      currentFloorId,
      previousFloorsFalseCount,
      currentFloorIsFalse,
      debugLogOn: majinWbDebugEnabled(),
      entryNameIncludes: ENTRY_NAME_INCLUDES,
    };
    console.info(LOG_PREFIX, '__majinWbDump', o);
    return o;
  };

  const dumpEntries = async () => {
    const wb = getPrimaryWorldbookName();
    if (!wb) {
      console.warn(LOG_PREFIX, '__majinWbDumpEntries: 当前角色无主世界书 primary');
      return;
    }
    const entries = await getWorldbook(wb);
    const hits = entries.filter(e => (e?.name ?? '').includes(ENTRY_NAME_INCLUDES));
    console.info(LOG_PREFIX, `世界书「${wb}」中含「${ENTRY_NAME_INCLUDES}」的条目 (${hits.length}):`);
    console.table(
      hits.map(e => ({
        name: e.name,
        strategyType: e.strategy?.type,
        enabled: e.enabled,
      })),
    );
    return { wb, hits };
  };

  const g = globalThis as any;
  g.__majinWbDump = dump;
  g.__majinWbDumpEntries = dumpEntries;
  try {
    if (window.top && window.top !== window) {
      const t = window.top as any;
      t.__majinWbDump = dump;
      t.__majinWbDumpEntries = dumpEntries;
    }
  } catch {
    /* cross-origin */
  }
}

let debounceTimer: ReturnType<typeof setTimeout> | null = null;

/** 已由输入框关键字触发、在「魔人化」被明确关之前保持蓝灯 */
let holdMajinWorldbook = false;

/** 当前检测的楼层 ID */
let currentFloorId = -1;

/** 当前楼层经过评估后是否为明确的 false */
let currentFloorIsFalse = false;

/** 在当前楼层之前，连续明确为 false 的楼层数 */
let previousFloorsFalseCount = 0;

/** 总计连续「新末楼」时读到魔人化明确为 false 的次数（当前如果为 false 则为 previous + 1） */
let majinFalseStreakCount = 0;

let lastPollSnapshot = '';
/** 当由启动触发蓝灯后，必须等待连续若干楼层明确为 false 才允许回绿 */
let requireFalseFloorsAfterLaunch = false;

function readHeroValueFromAnyShape(candidate: any, key: string): unknown {
  return (
    candidate?.stat_data?.主角?.[key] ??
    candidate?.stat_data?.stat_data?.主角?.[key] ??
    candidate?.主角?.[key] ??
    candidate?.mvu?.主角?.[key]
  );
}

function getHeroValue(key: string): unknown {
  const g = globalThis as any;
  try {
    if (g?.Mvu && typeof g.Mvu.getMvuData === 'function') {
      const byLatest = g.Mvu.getMvuData({ type: 'message', message_id: 'latest' }) ?? {};
      const v = readHeroValueFromAnyShape(byLatest, key);
      if (v !== undefined) return v;
    }
  } catch {
    /* ignore */
  }

  const scopes: Array<{ type: Parameters<typeof getVariables>[0]['type']; message_id?: number | string }> = [
    { type: 'message', message_id: 'latest' },
    { type: 'chat' },
    { type: 'character' },
    { type: 'global' },
  ];

  for (const scope of scopes) {
    try {
      const v = getVariables(scope as any) as any;
      const got = readHeroValueFromAnyShape(v, key);
      if (got !== undefined) return got;
    } catch {
      /* ignore */
    }
  }

  return undefined;
}

/** 仅当变量明确为「关」时返回 true；undefined/null 等不视为关 */
function isMajinizationExplicitlyFalse(raw: unknown): boolean {
  if (raw === false || raw === 0) return true;

  // 只把“明确关闭”当作 false：避免把 undefined/null 误判成 false
  if (typeof raw === 'string') {
    const t = raw.trim();
    if (!t) return false;
    const tl = t.toLowerCase();

    if (tl === 'false') return true;
    if (t === '0') return true;
    if (/^(否|关|关闭|off)$/i.test(t)) return true;
  }

  return false;
}

/** 末楼 id 变化 = 新的一楼：用当前读到的魔人化更新连击（在 sync 内调用，不依赖 MESSAGE_* 是否触发） */
function updateFalseStreakOnLatestFloor(): void {
  // 获取真正的当前楼层ID (而不是可能被某些脚本缓存的旧ID)
  const curId = getLastMessageId();
  if (curId < 0) return;

  // 在拿到当前楼层 ID 后再读取主角魔人化变量，确保与楼层对应
  const rawMajin = getHeroValue(MAJIN_KEY);
  const isFalse = isMajinizationExplicitlyFalse(rawMajin);

  // 避免在重新加载页面时重复计算旧消息
  if (currentFloorId === -1) {
    currentFloorId = curId;
    currentFloorIsFalse = isFalse;
    if (isFalse) {
      majinFalseStreakCount = 1;
    }
    return;
  }

  // 检测楼层是否发生了改变 (用户发消息或AI开始回复)
  if (curId !== currentFloorId) {
    if (currentFloorIsFalse) {
      previousFloorsFalseCount += 1;
    } else {
      previousFloorsFalseCount = 0;
    }
    currentFloorId = curId;
  }

  currentFloorIsFalse = isFalse;
  if (currentFloorIsFalse) {
    majinFalseStreakCount = previousFloorsFalseCount + 1;
  } else {
    majinFalseStreakCount = 0;
    previousFloorsFalseCount = 0;
  }

  majinWbLog('falseStreak 更新', {
    curId,
    currentFloorId,
    currentFloorIsFalse,
    previousFloorsFalseCount,
    majinFalseStreakCount,
    raw: rawMajin,
  });
}

function resetFalseStreakState(): void {
  majinFalseStreakCount = 0;
  previousFloorsFalseCount = 0;
  currentFloorIsFalse = false;
  // currentFloorId 保持不变，以便在同一楼层内不会重复增加 previous
}

function scheduleSync(): void {
  if (debounceTimer) clearTimeout(debounceTimer);
  debounceTimer = setTimeout(() => {
    debounceTimer = null;
    void errorCatched(syncWorldbookMj)();
  }, DEBOUNCE_MS);
}

function getPrimaryWorldbookName(): string | null {
  try {
    const { primary } = getCharWorldbookNames('current');
    const n = primary?.trim();
    return n ? n : null;
  } catch {
    return null;
  }
}

/** 当前聊天最后一楼是否为用户消息且含启动关键字（用于发送后输入框已清空仍保持蓝灯） */
function lastMessageIsUserWithLaunch(): boolean {
  try {
    const n = getLastMessageId();
    if (n < 0) return false;
    const msgs = getChatMessages(n);
    const m = msgs[0];
    if (!m) return false;
    const isUser = m.is_user === true || m.is_user === 'true' || m.is_user === 1;
    if (!isUser) return false;
    return String(m.message ?? '').includes(LAUNCH_TEXT);
  } catch {
    return false;
  }
}

function readTopSendTextareaText(): string {
  try {
    const doc = window.top?.document;
    if (!doc) return '';
    const el = doc.querySelector(
      '#send_textarea, textarea[name="send_textarea"], textarea#send_textarea, #send_text, textarea[data-testid="send_textarea"], textarea.mes_textarea',
    ) as HTMLTextAreaElement | null;
    if (!el) return '';
    return String(el.value ?? '').trim();
  } catch {
    return '';
  }
}

function bindTopSendTextareaHooks(): void {
  try {
    const doc = window.top?.document;
    if (!doc) {
      majinWbLog('bindTopSendTextareaHooks: window.top.document 不可用（可能跨域或尚未就绪）');
      return;
    }
    const textarea = doc.querySelector(
      '#send_textarea, textarea[name="send_textarea"], textarea#send_textarea, #send_text, textarea[data-testid="send_textarea"], textarea.mes_textarea',
    ) as HTMLTextAreaElement | null;
    if (!textarea) {
      majinWbLog('bindTopSendTextareaHooks: 未找到顶层发送框 textarea，输入监听不会生效');
      return;
    }

    const mark = '__mjjinBound__';
    if ((textarea as any)[mark]) {
      majinWbLog('bindTopSendTextareaHooks: 已绑定过，跳过');
      return;
    }
    (textarea as any)[mark] = true;

    majinWbLog('已绑定顶层发送框', { id: textarea.id, name: (textarea as HTMLTextAreaElement).name });

    const onTextMaybeChanged = () => {
      scheduleSync();
    };

    textarea.addEventListener('input', onTextMaybeChanged);
    textarea.addEventListener('paste', onTextMaybeChanged);
    textarea.addEventListener('cut', onTextMaybeChanged);
    textarea.addEventListener('keydown', ev => {
      if (ev.key !== 'Enter') return;
      if (ev.shiftKey || ev.ctrlKey || ev.altKey) return;
      onTextMaybeChanged();
    });

    onTextMaybeChanged();
  } catch (e) {
    majinWbLog('bindTopSendTextareaHooks 异常', e);
  }
}

function snapshotForPoll(): string {
  const textHas = readTopSendTextareaText().includes(LAUNCH_TEXT);
  const raw = getHeroValue(MAJIN_KEY);
  let rawTag: string;
  if (raw === undefined) rawTag = 'undef';
  else if (raw === null) rawTag = 'null';
  else if (typeof raw === 'object') rawTag = JSON.stringify(raw);
  else rawTag = String(raw);
  return `${textHas}|${rawTag}|${holdMajinWorldbook}|${lastMessageIsUserWithLaunch()}|${majinFalseStreakCount}|${getLastMessageId()}`;
}

function maybePollSchedule(): void {
  const snap = snapshotForPoll();
  if (snap === lastPollSnapshot) return;
  majinWbLog('poll 快照变化 → scheduleSync', snap);
  lastPollSnapshot = snap;
  scheduleSync();
}

function startMajinPoll(): void {
  if ((globalThis as any).__majinWbPollTimer) return;
  const timer = setInterval(() => {
    maybePollSchedule();
  }, HERO_POLL_MS);
  (globalThis as any).__majinWbPollTimer = timer;
}

async function syncWorldbookMj(): Promise<void> {
  const wbName = getPrimaryWorldbookName();
  if (!wbName) {
    majinWbLog('sync: 无主世界书 getCharWorldbookNames("current").primary，已跳过');
    return;
  }

  const textHas = readTopSendTextareaText().includes(LAUNCH_TEXT);
  const rawMajin = getHeroValue(MAJIN_KEY);
  const lastUserLaunch = lastMessageIsUserWithLaunch();

  updateFalseStreakOnLatestFloor();

  // 输入框有关键字：优先蓝（避免正在打字时被下面的绿灯拉掉）
  if (textHas) {
    // 新的启动发生：把计数重置，强制等待后续楼层确认为 false
    holdMajinWorldbook = true;
    requireFalseFloorsAfterLaunch = true;
    // 将 currentFloorId 同步为当前末楼，避免把当前楼误算为新楼
    try {
      currentFloorId = getLastMessageId();
    } catch {
      /* ignore */
    }

    // 同步当前锚点楼层的 false 状态，避免后续 curId 变化时出现 off-by-one
    currentFloorIsFalse = isMajinizationExplicitlyFalse(rawMajin);

    majinFalseStreakCount = 0;
    previousFloorsFalseCount = 0;
    // 连续FALSE_STREAK_FLOORS_NEEDED次新楼层且当前仍为明确false，且输入框无关键字
  } else if (
    majinFalseStreakCount >= FALSE_STREAK_FLOORS_NEEDED &&
    isMajinizationExplicitlyFalse(rawMajin) &&
    !textHas
  ) {
    // 连续两楼末楼时刻均为明确 false：绿灯
    // 只有在不是刚由启动触发的等待期间才直接清除；若是启动后，则在满足连击后清除标志
    if (!requireFalseFloorsAfterLaunch) {
      // 已经经过启动后的等待阶段：第二次满足阈值才真正回绿
      holdMajinWorldbook = false;
      requireFalseFloorsAfterLaunch = false;
      resetFalseStreakState();
    } else {
      // 第一次满足阈值（通常发生在“触发蓝灯后的下一楼”）
      // 此时仍保持蓝灯，只把等待标志清掉，让下一楼再触发转绿
      requireFalseFloorsAfterLaunch = false;
      holdMajinWorldbook = true;
    }
  } else if (lastUserLaunch) {
    // 用户刚发送包含启动关键字的消息（发送后输入框已清空）
    // 将其视为一次新的启动：进入等待连续 false 的阶段
    holdMajinWorldbook = true;
    requireFalseFloorsAfterLaunch = true;
    try {
      currentFloorId = getLastMessageId();
    } catch {
      /* ignore */
    }

    // 同步当前锚点楼层的 false 状态，避免后续 curId 变化时出现 off-by-one
    currentFloorIsFalse = isMajinizationExplicitlyFalse(rawMajin);

    majinFalseStreakCount = 0;
    previousFloorsFalseCount = 0;
  }

  lastPollSnapshot = snapshotForPoll();

  const nextType: 'constant' | 'selective' = holdMajinWorldbook ? 'constant' : 'selective';

  const entries = await getWorldbook(wbName);
  const matched = entries.filter(e => {
    const name = e?.name ?? '';
    return name.includes(ENTRY_NAME_INCLUDES) && e?.strategy?.type !== 'vectorized';
  });

  let needsWrite = false;
  for (const entry of matched) {
    if (entry.strategy?.type !== nextType) {
      needsWrite = true;
      break;
    }
  }

  majinWbLog('sync', {
    wbName,
    textHas,
    lastUserLaunch,
    raw主角魔人化: rawMajin,
    explicitlyFalse: isMajinizationExplicitlyFalse(rawMajin),
    majinFalseStreakCount,
    falseStreakNeeded: FALSE_STREAK_FLOORS_NEEDED,
    holdMajinWorldbook,
    nextType,
    matchedCount: matched.length,
    matchedSummary: matched.map(e => ({ name: e.name, type: e.strategy?.type })),
    needsWrite,
  });

  if (matched.length === 0) {
    majinWbLog(
      '提示: 主世界书中没有「名称包含',
      ENTRY_NAME_INCLUDES,
      '」且非 vectorized 的条目；请核对条目命名或改脚本常量 ENTRY_NAME_INCLUDES',
    );
  }

  if (!needsWrite) return;

  majinWbLog('执行 updateWorldbookWith →', nextType);
  await updateWorldbookWith(wbName, draft => {
    for (const entry of draft) {
      const name = entry?.name ?? '';
      if (!name.includes(ENTRY_NAME_INCLUDES)) continue;
      if (entry?.strategy?.type === 'vectorized') continue;
      if (entry.strategy?.type !== nextType) {
        entry.strategy = { ...(entry.strategy || {}), type: nextType };
      }
    }
    return draft;
  });
}

$(() => {
  errorCatched(() => {
    exposeDebugHelpers();
    if (majinWbDebugEnabled()) {
      console.info(LOG_PREFIX, '调试日志已开启（MAJIN_WB_DEBUG_FORCE 或 localStorage', LS_DEBUG_KEY, '）');
    } else {
      console.info(
        LOG_PREFIX,
        '已加载。排查无反应可执行: localStorage.setItem("' +
          LS_DEBUG_KEY +
          '","1") 后重载脚本，或调用 __majinWbDump() / __majinWbDumpEntries()',
      );
    }

    bindTopSendTextareaHooks();

    void syncWorldbookMj();

    eventOn(tavern_events.MESSAGE_SENT, scheduleSync);
    eventOn(tavern_events.MESSAGE_RECEIVED, scheduleSync);
    eventOn(tavern_events.MESSAGE_UPDATED, scheduleSync);
    eventOn(tavern_events.CHAT_CHANGED, () => {
      holdMajinWorldbook = false;
      resetFalseStreakState();
      lastPollSnapshot = '';
      scheduleSync();
    });
    eventOn(tavern_events.CHARACTER_PAGE_LOADED, () => {
      holdMajinWorldbook = false;
      resetFalseStreakState();
      lastPollSnapshot = '';
      scheduleSync();
    });

    startMajinPoll();

    $(window).on('pagehide', () => {
      const t = (globalThis as any).__majinWbPollTimer;
      if (t) clearInterval(t);
      (globalThis as any).__majinWbPollTimer = null;
    });
  })();
});
